namespace sv_174bd80ee7864801aaffa52e19d601d0.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            "PKG-001",
            "In Transit",
            "Memphis, TN",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Arrived at sorting facility", DateTimeOffset.UtcNow.AddDays(-2)),
                new("Departed Memphis, TN", DateTimeOffset.UtcNow.AddDays(-1)),
            }),
        ["PKG-002"] = new Shipment(
            "PKG-002",
            "Delivered",
            "Austin, TX",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-5)),
                new("In transit", DateTimeOffset.UtcNow.AddDays(-4)),
                new("Out for delivery", DateTimeOffset.UtcNow.AddDays(-1)),
                new("Delivered - Left at front door", DateTimeOffset.UtcNow.AddDays(-1).AddHours(3)),
            }),
        ["PKG-003"] = new Shipment(
            "PKG-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new("Label created", DateTimeOffset.UtcNow.AddHours(-6)),
                new("Awaiting carrier pickup", DateTimeOffset.UtcNow.AddHours(-2)),
            }),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Tracking number '{trackingNumber}' not found.");
    }
}
